import os
import json

def read_word_document(file_path: str) -> str:
    """Read a Word document and extract all content including paragraphs, tables, styles, and metadata.

    Args:
        file_path: Path to the .docx file to read

    Returns:
        A detailed string representation of the document contents
    """
    try:
        from docx import Document
        from docx.enum.text import WD_ALIGN_PARAGRAPH

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        if not file_path.lower().endswith('.docx'):
            return f"Error: File must be a .docx file. Got: {file_path}"

        doc = Document(file_path)
        result = []

        # Document properties
        props = doc.core_properties
        result.append('=== DOCUMENT METADATA ===')
        if props.title:
            result.append(f'Title: {props.title}')
        if props.author:
            result.append(f'Author: {props.author}')
        if props.created:
            result.append(f'Created: {props.created}')
        if props.modified:
            result.append(f'Modified: {props.modified}')
        result.append('')

        # Sections info
        result.append(f'=== DOCUMENT STRUCTURE ===')
        result.append(f'Sections: {len(doc.sections)}')
        result.append(f'Paragraphs: {len(doc.paragraphs)}')
        result.append(f'Tables: {len(doc.tables)}')
        result.append('')

        # Content
        result.append('=== DOCUMENT CONTENT ===')
        for i, para in enumerate(doc.paragraphs):
            style_name = para.style.name if para.style else 'Normal'
            text = para.text.strip()
            if text or style_name.startswith('Heading'):
                # Check formatting
                formatting = []
                for run in para.runs:
                    if run.bold:
                        formatting.append('bold')
                    if run.italic:
                        formatting.append('italic')
                    if run.underline:
                        formatting.append('underline')
                fmt_str = f' [{", ".join(set(formatting))}]' if formatting else ''
                result.append(f'[P{i}] [{style_name}]{fmt_str}: {text}')

        # Tables
        for t_idx, table in enumerate(doc.tables):
            result.append(f'\n=== TABLE {t_idx + 1} ({len(table.rows)} rows x {len(table.columns)} cols) ===')
            for r_idx, row in enumerate(table.rows):
                cells = [cell.text.strip() for cell in row.cells]
                result.append(f'  Row {r_idx}: {" | ".join(cells)}')

        # Headers and footers
        for s_idx, section in enumerate(doc.sections):
            header = section.header
            footer = section.footer
            if header and header.paragraphs:
                header_text = ' '.join(p.text for p in header.paragraphs if p.text.strip())
                if header_text:
                    result.append(f'\n=== HEADER (Section {s_idx + 1}) ===')
                    result.append(header_text)
            if footer and footer.paragraphs:
                footer_text = ' '.join(p.text for p in footer.paragraphs if p.text.strip())
                if footer_text:
                    result.append(f'\n=== FOOTER (Section {s_idx + 1}) ===')
                    result.append(footer_text)

        return '\n'.join(result)
    except Exception as e:
        return f"Error reading Word document: {str(e)}"


def get_document_text(file_path: str) -> str:
    """Get plain text content from a Word document (simple extraction).

    Args:
        file_path: Path to the .docx file

    Returns:
        Plain text content of the document
    """
    try:
        from docx import Document

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)
        paragraphs = [p.text for p in doc.paragraphs if p.text.strip()]
        return '\n\n'.join(paragraphs)
    except Exception as e:
        return f"Error: {str(e)}"

import os
import json

def create_word_document(output_path: str, content_json: str, title: str = '', author: str = '') -> str:
    """Create a new Word document with rich content.

    Args:
        output_path: Path where the .docx file will be saved
        content_json: JSON string describing the document content. It should be a JSON array of content blocks.
            Each block is an object with a 'type' field and additional fields depending on type:

            - {"type": "heading", "text": "...", "level": 1}  (level 0-4, 0=Title)
            - {"type": "paragraph", "text": "...", "bold": false, "italic": false, "alignment": "left"}
            - {"type": "bullet_list", "items": ["item1", "item2", ...]}
            - {"type": "numbered_list", "items": ["item1", "item2", ...]}
            - {"type": "table", "headers": ["col1", "col2"], "rows": [["a","b"],["c","d"]]}
            - {"type": "image", "path": "/path/to/image.png", "width_inches": 4}
            - {"type": "page_break"}
            - {"type": "rich_paragraph", "runs": [{"text": "bold text", "bold": true}, {"text": " normal"}]}
        title: Optional document title metadata
        author: Optional document author metadata

    Returns:
        Success message with the file path, or error message
    """
    try:
        from docx import Document
        from docx.shared import Inches, Pt, RGBColor
        from docx.enum.text import WD_ALIGN_PARAGRAPH
        from docx.enum.table import WD_TABLE_ALIGNMENT

        doc = Document()

        # Set metadata
        if title:
            doc.core_properties.title = title
        if author:
            doc.core_properties.author = author

        # Parse content
        try:
            content_blocks = json.loads(content_json)
        except json.JSONDecodeError as e:
            return f"Error parsing content JSON: {str(e)}"

        if not isinstance(content_blocks, list):
            return "Error: content_json must be a JSON array of content blocks"

        alignment_map = {
            'left': WD_ALIGN_PARAGRAPH.LEFT,
            'center': WD_ALIGN_PARAGRAPH.CENTER,
            'right': WD_ALIGN_PARAGRAPH.RIGHT,
            'justify': WD_ALIGN_PARAGRAPH.JUSTIFY
        }

        for block in content_blocks:
            block_type = block.get('type', '')

            if block_type == 'heading':
                level = block.get('level', 1)
                text = block.get('text', '')
                heading = doc.add_heading(text, level=level)
                if block.get('alignment'):
                    heading.alignment = alignment_map.get(block['alignment'], WD_ALIGN_PARAGRAPH.LEFT)

            elif block_type == 'paragraph':
                para = doc.add_paragraph()
                if block.get('alignment'):
                    para.alignment = alignment_map.get(block['alignment'], WD_ALIGN_PARAGRAPH.LEFT)
                run = para.add_run(block.get('text', ''))
                if block.get('bold'):
                    run.bold = True
                if block.get('italic'):
                    run.italic = True
                if block.get('underline'):
                    run.underline = True
                if block.get('font_size'):
                    run.font.size = Pt(block['font_size'])
                if block.get('font_color'):
                    color = block['font_color'].lstrip('#')
                    run.font.color.rgb = RGBColor(int(color[0:2], 16), int(color[2:4], 16), int(color[4:6], 16))

            elif block_type == 'rich_paragraph':
                para = doc.add_paragraph()
                if block.get('alignment'):
                    para.alignment = alignment_map.get(block['alignment'], WD_ALIGN_PARAGRAPH.LEFT)
                for run_data in block.get('runs', []):
                    run = para.add_run(run_data.get('text', ''))
                    if run_data.get('bold'):
                        run.bold = True
                    if run_data.get('italic'):
                        run.italic = True
                    if run_data.get('underline'):
                        run.underline = True
                    if run_data.get('font_size'):
                        run.font.size = Pt(run_data['font_size'])
                    if run_data.get('font_color'):
                        color = run_data['font_color'].lstrip('#')
                        run.font.color.rgb = RGBColor(int(color[0:2], 16), int(color[2:4], 16), int(color[4:6], 16))

            elif block_type == 'bullet_list':
                for item in block.get('items', []):
                    doc.add_paragraph(item, style='List Bullet')

            elif block_type == 'numbered_list':
                for item in block.get('items', []):
                    doc.add_paragraph(item, style='List Number')

            elif block_type == 'table':
                headers = block.get('headers', [])
                rows = block.get('rows', [])
                if headers:
                    table = doc.add_table(rows=1 + len(rows), cols=len(headers))
                    table.style = 'Table Grid'
                    table.alignment = WD_TABLE_ALIGNMENT.CENTER
                    # Header row
                    for i, header in enumerate(headers):
                        cell = table.rows[0].cells[i]
                        cell.text = str(header)
                        for paragraph in cell.paragraphs:
                            for run in paragraph.runs:
                                run.bold = True
                    # Data rows
                    for r_idx, row in enumerate(rows):
                        for c_idx, cell_text in enumerate(row):
                            if c_idx < len(headers):
                                table.rows[r_idx + 1].cells[c_idx].text = str(cell_text)
                    doc.add_paragraph()  # spacing after table

            elif block_type == 'image':
                img_path = block.get('path', '')
                if os.path.exists(img_path):
                    width = Inches(block.get('width_inches', 4))
                    doc.add_picture(img_path, width=width)
                else:
                    doc.add_paragraph(f'[Image not found: {img_path}]')

            elif block_type == 'page_break':
                doc.add_page_break()

        # Ensure output directory exists
        out_dir = os.path.dirname(output_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)

        doc.save(output_path)
        url = save_artifact(output_path)
        return f"Document created successfully: {output_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error creating document: {str(e)}"

import os
import json

def replace_text_in_document(file_path: str, search_text: str, replace_text: str, output_path: str = '') -> str:
    """Find and replace text throughout a Word document (paragraphs, tables, headers, footers).

    Args:
        file_path: Path to the source .docx file
        search_text: Text to search for
        replace_text: Text to replace with
        output_path: Path to save the modified document (defaults to overwriting the original)

    Returns:
        Success message with replacement count
    """
    try:
        from docx import Document

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)
        count = 0

        # Replace in paragraphs
        for para in doc.paragraphs:
            if search_text in para.text:
                for run in para.runs:
                    if search_text in run.text:
                        run.text = run.text.replace(search_text, replace_text)
                        count += 1

        # Replace in tables
        for table in doc.tables:
            for row in table.rows:
                for cell in row.cells:
                    for para in cell.paragraphs:
                        if search_text in para.text:
                            for run in para.runs:
                                if search_text in run.text:
                                    run.text = run.text.replace(search_text, replace_text)
                                    count += 1

        # Replace in headers/footers
        for section in doc.sections:
            for para in section.header.paragraphs:
                if search_text in para.text:
                    for run in para.runs:
                        if search_text in run.text:
                            run.text = run.text.replace(search_text, replace_text)
                            count += 1
            for para in section.footer.paragraphs:
                if search_text in para.text:
                    for run in para.runs:
                        if search_text in run.text:
                            run.text = run.text.replace(search_text, replace_text)
                            count += 1

        save_path = output_path if output_path else file_path
        out_dir = os.path.dirname(save_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)
        doc.save(save_path)
        url = save_artifact(save_path)
        return f"Replaced {count} occurrence(s) of '{search_text}'. Saved to: {save_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error: {str(e)}"


def append_content_to_document(file_path: str, content_json: str, output_path: str = '') -> str:
    """Append new content blocks to the end of an existing Word document.

    Args:
        file_path: Path to the source .docx file
        content_json: JSON string of content blocks to append (same format as create_word_document)
            Each block is an object with a 'type' field:
            - {"type": "heading", "text": "...", "level": 1}
            - {"type": "paragraph", "text": "...", "bold": false, "italic": false}
            - {"type": "bullet_list", "items": ["item1", "item2"]}
            - {"type": "numbered_list", "items": ["item1", "item2"]}
            - {"type": "table", "headers": ["col1"], "rows": [["val"]]}
            - {"type": "page_break"}
        output_path: Path to save modified document (defaults to overwriting original)

    Returns:
        Success message
    """
    try:
        from docx import Document
        from docx.shared import Inches, Pt
        from docx.enum.table import WD_TABLE_ALIGNMENT

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)
        blocks = json.loads(content_json)

        for block in blocks:
            block_type = block.get('type', '')

            if block_type == 'heading':
                doc.add_heading(block.get('text', ''), level=block.get('level', 1))
            elif block_type == 'paragraph':
                para = doc.add_paragraph()
                run = para.add_run(block.get('text', ''))
                if block.get('bold'):
                    run.bold = True
                if block.get('italic'):
                    run.italic = True
            elif block_type == 'bullet_list':
                for item in block.get('items', []):
                    doc.add_paragraph(item, style='List Bullet')
            elif block_type == 'numbered_list':
                for item in block.get('items', []):
                    doc.add_paragraph(item, style='List Number')
            elif block_type == 'table':
                headers = block.get('headers', [])
                rows = block.get('rows', [])
                if headers:
                    table = doc.add_table(rows=1 + len(rows), cols=len(headers))
                    table.style = 'Table Grid'
                    for i, h in enumerate(headers):
                        cell = table.rows[0].cells[i]
                        cell.text = str(h)
                        for p in cell.paragraphs:
                            for r in p.runs:
                                r.bold = True
                    for r_idx, row in enumerate(rows):
                        for c_idx, val in enumerate(row):
                            if c_idx < len(headers):
                                table.rows[r_idx + 1].cells[c_idx].text = str(val)
            elif block_type == 'page_break':
                doc.add_page_break()

        save_path = output_path if output_path else file_path
        out_dir = os.path.dirname(save_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)
        doc.save(save_path)
        url = save_artifact(save_path)
        return f"Content appended successfully. Saved to: {save_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error: {str(e)}"


def delete_paragraph_by_index(file_path: str, paragraph_index: int, output_path: str = '') -> str:
    """Delete a specific paragraph from a Word document by its index.

    Args:
        file_path: Path to the .docx file
        paragraph_index: Zero-based index of the paragraph to delete
        output_path: Path to save modified document (defaults to overwriting original)

    Returns:
        Success message
    """
    try:
        from docx import Document

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)

        if paragraph_index < 0 or paragraph_index >= len(doc.paragraphs):
            return f"Error: Paragraph index {paragraph_index} out of range. Document has {len(doc.paragraphs)} paragraphs."

        para = doc.paragraphs[paragraph_index]
        p_element = para._element
        p_element.getparent().remove(p_element)

        save_path = output_path if output_path else file_path
        out_dir = os.path.dirname(save_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)
        doc.save(save_path)
        url = save_artifact(save_path)
        return f"Paragraph {paragraph_index} deleted. Saved to: {save_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error: {str(e)}"


def update_paragraph_text(file_path: str, paragraph_index: int, new_text: str, output_path: str = '') -> str:
    """Update the text of a specific paragraph by index, preserving the style.

    Args:
        file_path: Path to the .docx file
        paragraph_index: Zero-based index of the paragraph to update
        new_text: New text for the paragraph
        output_path: Path to save modified document (defaults to overwriting original)

    Returns:
        Success message
    """
    try:
        from docx import Document

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)

        if paragraph_index < 0 or paragraph_index >= len(doc.paragraphs):
            return f"Error: Index {paragraph_index} out of range. Document has {len(doc.paragraphs)} paragraphs."

        para = doc.paragraphs[paragraph_index]
        # Clear existing runs
        for run in para.runs:
            run.text = ''
        if para.runs:
            para.runs[0].text = new_text
        else:
            para.add_run(new_text)

        save_path = output_path if output_path else file_path
        out_dir = os.path.dirname(save_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)
        doc.save(save_path)
        url = save_artifact(save_path)
        return f"Paragraph {paragraph_index} updated. Saved to: {save_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error: {str(e)}"


def set_header_footer(file_path: str, header_text: str = '', footer_text: str = '', output_path: str = '') -> str:
    """Set the header and/or footer text for all sections of a Word document.

    Args:
        file_path: Path to the .docx file
        header_text: Text to set as the header (empty to leave unchanged)
        footer_text: Text to set as the footer (empty to leave unchanged)
        output_path: Path to save modified document (defaults to overwriting original)

    Returns:
        Success message
    """
    try:
        from docx import Document
        from docx.enum.text import WD_ALIGN_PARAGRAPH

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)

        for section in doc.sections:
            if header_text:
                header = section.header
                header.is_linked_to_previous = False
                if header.paragraphs:
                    header.paragraphs[0].text = header_text
                else:
                    header.add_paragraph(header_text)
            if footer_text:
                footer = section.footer
                footer.is_linked_to_previous = False
                if footer.paragraphs:
                    footer.paragraphs[0].text = footer_text
                else:
                    footer.add_paragraph(footer_text)

        save_path = output_path if output_path else file_path
        out_dir = os.path.dirname(save_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)
        doc.save(save_path)
        url = save_artifact(save_path)
        return f"Header/footer updated. Saved to: {save_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error: {str(e)}"

import os
import json
import re

def markdown_to_word(markdown_text: str, output_path: str) -> str:
    """Convert Markdown text to a formatted Word document. Supports headings, bold, italic, code blocks, lists, tables, links, and horizontal rules.

    Args:
        markdown_text: The Markdown content to convert
        output_path: Path where the .docx file will be saved

    Returns:
        Success message with file path
    """
    try:
        from docx import Document
        from docx.shared import Pt, Inches, RGBColor
        from docx.enum.text import WD_ALIGN_PARAGRAPH
        import markdown
        from bs4 import BeautifulSoup

        doc = Document()

        # Convert markdown to HTML first
        html = markdown.markdown(
            markdown_text, 
            extensions=['tables', 'fenced_code', 'codehilite', 'nl2br', 'sane_lists']
        )
        soup = BeautifulSoup(html, 'html.parser')

        def _add_inline_formatting(paragraph, element):
            """Recursively add inline formatting to a paragraph."""
            if isinstance(element, str):
                paragraph.add_run(element)
                return

            tag = element.name

            if tag in ('strong', 'b'):
                for child in element.children:
                    if isinstance(child, str):
                        run = paragraph.add_run(child)
                        run.bold = True
                    else:
                        _add_inline_formatting(paragraph, child)
            elif tag in ('em', 'i'):
                for child in element.children:
                    if isinstance(child, str):
                        run = paragraph.add_run(child)
                        run.italic = True
                    else:
                        _add_inline_formatting(paragraph, child)
            elif tag == 'code':
                run = paragraph.add_run(element.get_text())
                run.font.name = 'Courier New'
                run.font.size = Pt(9)
                run.font.color.rgb = RGBColor(0x80, 0x80, 0x80)
            elif tag == 'a':
                text = element.get_text()
                href = element.get('href', '')
                run = paragraph.add_run(f"{text} ({href})" if href else text)
                run.font.color.rgb = RGBColor(0x05, 0x63, 0xC1)
                run.underline = True
            elif tag == 'br':
                paragraph.add_run('\n')
            else:
                for child in element.children:
                    _add_inline_formatting(paragraph, child)

        def _process_element(element):
            """Process a top-level HTML element into the Word document."""
            if isinstance(element, str):
                text = element.strip()
                if text:
                    doc.add_paragraph(text)
                return

            tag = element.name

            # Headings
            if tag in ('h1', 'h2', 'h3', 'h4', 'h5', 'h6'):
                level = int(tag[1])
                heading = doc.add_heading(level=min(level, 4))
                for child in element.children:
                    _add_inline_formatting(heading, child)

            # Paragraphs
            elif tag == 'p':
                para = doc.add_paragraph()
                for child in element.children:
                    _add_inline_formatting(para, child)

            # Unordered list
            elif tag == 'ul':
                for li in element.find_all('li', recursive=False):
                    para = doc.add_paragraph(style='List Bullet')
                    for child in li.children:
                        if isinstance(child, str):
                            para.add_run(child.strip())
                        elif child.name in ('ul', 'ol'):
                            pass  # Nested lists simplified
                        else:
                            _add_inline_formatting(para, child)

            # Ordered list
            elif tag == 'ol':
                for li in element.find_all('li', recursive=False):
                    para = doc.add_paragraph(style='List Number')
                    for child in li.children:
                        if isinstance(child, str):
                            para.add_run(child.strip())
                        elif child.name in ('ul', 'ol'):
                            pass
                        else:
                            _add_inline_formatting(para, child)

            # Code blocks
            elif tag == 'pre':
                code_text = element.get_text()
                para = doc.add_paragraph()
                run = para.add_run(code_text)
                run.font.name = 'Courier New'
                run.font.size = Pt(9)

            # Tables
            elif tag == 'table':
                rows_data = []
                thead = element.find('thead')
                tbody = element.find('tbody')

                if thead:
                    for tr in thead.find_all('tr'):
                        row = [th.get_text().strip() for th in tr.find_all(['th', 'td'])]
                        rows_data.append(row)
                if tbody:
                    for tr in tbody.find_all('tr'):
                        row = [td.get_text().strip() for td in tr.find_all(['td', 'th'])]
                        rows_data.append(row)
                if not thead and not tbody:
                    for tr in element.find_all('tr'):
                        row = [td.get_text().strip() for td in tr.find_all(['td', 'th'])]
                        rows_data.append(row)

                if rows_data:
                    max_cols = max(len(r) for r in rows_data)
                    table = doc.add_table(rows=len(rows_data), cols=max_cols)
                    table.style = 'Table Grid'
                    for r_idx, row in enumerate(rows_data):
                        for c_idx, cell_text in enumerate(row):
                            if c_idx < max_cols:
                                table.rows[r_idx].cells[c_idx].text = cell_text
                    # Bold header row
                    if len(rows_data) > 0:
                        for cell in table.rows[0].cells:
                            for p in cell.paragraphs:
                                for r in p.runs:
                                    r.bold = True
                    doc.add_paragraph()  # spacing

            # Horizontal rule
            elif tag == 'hr':
                para = doc.add_paragraph()
                para.add_run('─' * 50)
                para.alignment = WD_ALIGN_PARAGRAPH.CENTER

            # Blockquote
            elif tag == 'blockquote':
                text = element.get_text().strip()
                para = doc.add_paragraph()
                run = para.add_run(f'│ {text}')
                run.italic = True
                run.font.color.rgb = RGBColor(0x66, 0x66, 0x66)

        for element in soup.children:
            _process_element(element)

        out_dir = os.path.dirname(output_path)
        if out_dir:
            os.makedirs(out_dir, exist_ok=True)
        doc.save(output_path)
        url = save_artifact(output_path)
        return f"Markdown converted to Word successfully: {output_path}\n\nDownload: {url}"
    except Exception as e:
        return f"Error converting Markdown to Word: {str(e)}"


def word_to_markdown(file_path: str, output_path: str = '') -> str:
    """Convert a Word document to Markdown format.

    Args:
        file_path: Path to the .docx file to convert
        output_path: Optional path to save the .md file. If empty, returns the markdown text directly.

    Returns:
        The markdown text, or success message if saved to file
    """
    try:
        from docx import Document

        if not os.path.exists(file_path):
            return f"Error: File not found: {file_path}"

        doc = Document(file_path)
        md_lines = []

        # Track which elements we've processed through tables
        table_indices = set()

        # Build a sequential list of document elements
        from docx.oxml.ns import qn
        body = doc.element.body

        para_idx = 0
        table_idx = 0

        for child in body:
            if child.tag == qn('w:p'):
                if para_idx < len(doc.paragraphs):
                    para = doc.paragraphs[para_idx]
                    style_name = para.style.name if para.style else 'Normal'
                    text = para.text.strip()

                    # Headings
                    if style_name.startswith('Heading'):
                        try:
                            level = int(style_name.split()[-1])
                        except ValueError:
                            level = 1
                        md_lines.append(f"{'#' * level} {text}")
                        md_lines.append('')
                    elif style_name == 'Title':
                        md_lines.append(f"# {text}")
                        md_lines.append('')
                    elif style_name == 'Subtitle':
                        md_lines.append(f"## {text}")
                        md_lines.append('')
                    elif 'List Bullet' in style_name:
                        # Reconstruct inline formatting
                        formatted = _runs_to_md(para.runs)
                        md_lines.append(f"- {formatted}")
                    elif 'List Number' in style_name:
                        formatted = _runs_to_md(para.runs)
                        md_lines.append(f"1. {formatted}")
                    elif text:
                        formatted = _runs_to_md(para.runs)
                        md_lines.append(formatted)
                        md_lines.append('')
                    else:
                        md_lines.append('')

                    para_idx += 1

            elif child.tag == qn('w:tbl'):
                if table_idx < len(doc.tables):
                    table = doc.tables[table_idx]
                    if len(table.rows) > 0:
                        # Header row
                        headers = [cell.text.strip() for cell in table.rows[0].cells]
                        md_lines.append('| ' + ' | '.join(headers) + ' |')
                        md_lines.append('| ' + ' | '.join(['---'] * len(headers)) + ' |')

                        # Data rows
                        for row in table.rows[1:]:
                            cells = [cell.text.strip().replace('|', '\\|') for cell in row.cells]
                            md_lines.append('| ' + ' | '.join(cells) + ' |')
                        md_lines.append('')
                    table_idx += 1

        md_text = '\n'.join(md_lines)

        # Clean up excessive blank lines
        while '\n\n\n' in md_text:
            md_text = md_text.replace('\n\n\n', '\n\n')
        md_text = md_text.strip() + '\n'

        if output_path:
            out_dir = os.path.dirname(output_path)
            if out_dir:
                os.makedirs(out_dir, exist_ok=True)
            with open(output_path, 'w', encoding='utf-8') as f:
                f.write(md_text)
            url = save_artifact(output_path)
            return f"Word document converted to Markdown: {output_path}\n\nDownload: {url}\n\nContent:\n{md_text}"
        else:
            return md_text
    except Exception as e:
        return f"Error converting Word to Markdown: {str(e)}"


def _runs_to_md(runs) -> str:
    """Convert Word runs to Markdown formatted text."""
    result = []
    for run in runs:
        text = run.text
        if not text:
            continue
        if run.bold and run.italic:
            text = f"***{text}***"
        elif run.bold:
            text = f"**{text}**"
        elif run.italic:
            text = f"*{text}*"
        if run.font and run.font.name and 'courier' in run.font.name.lower():
            text = f"`{run.text}`"
        result.append(text)
    return ''.join(result)


def markdown_file_to_word(md_file_path: str, output_path: str) -> str:
    """Read a Markdown file and convert it to a Word document.

    Args:
        md_file_path: Path to the .md file to read
        output_path: Path where the .docx file will be saved

    Returns:
        Success message with file path
    """
    try:
        if not os.path.exists(md_file_path):
            return f"Error: File not found: {md_file_path}"

        with open(md_file_path, 'r', encoding='utf-8') as f:
            md_text = f.read()

        return markdown_to_word(md_text, output_path)
    except Exception as e:
        return f"Error: {str(e)}"
